-- ============================================================================
-- digital-clr-fix.sql — 디지털인쇄 흑백/칼라 축 오적재 + S2 미배선 교정 (A2 C1)
-- ----------------------------------------------------------------------------
-- 권위: 인쇄상품 가격표 260527 디지털인쇄비(칼라 column) + 원본 백업
--       raw/webadmin/sql/_backup_digital_clr_rows_20260617.json (clr_cd 이력)
-- 모델: 디지털 상품 19종은 전부 칼라(CLR_000005 CMYK)전용·흑백 선택 없음.
--       사용자는 단면(POPT_000001) / 양면(POPT_000002)만 택일.
--       => 가격축 = print_opt_cd(면) × plt_siz_cd(판형) × min_qty(수량구간).
--          색축(흑백/칼라)은 use_dims·NON_QTY_DIMS 에 없으므로 매칭에 不참여 →
--          칼라 단가만 적재한다(흑백 행은 도달불가 死데이터).
--
-- 현재 결함(COMP_PRINT_DIGITAL_S1, 바인딩된 유일 comp):
--   POPT_000001(단면) = 흑백단면(3000/3500)  ← 칼라단면(4000/4500) 이어야 함
--   POPT_000002(양면) = 칼라'단면'값(4000/4500, 양면 라벨만)  ← 칼라양면(6000/7000) 이어야 함
--   => 단면 -1,000 / 양면 -2,000원/매 저청구. 진짜 칼라양면(6000)은 배선0 도달불가.
--
-- 교정: S1 의 212행(흑백 106 + 오라벨 106)을 칼라 단가 212행으로 치환.
--   단면 band → POPT_000001, 양면 band → POPT_000002 (둘 다 동일 comp S1 내부).
--   단가값 = 백업 CLR_000005 verbatim(날조 0). clr_cd = NULL(매칭축 아님).
--   S2(COMP_PRINT_DIGITAL_S2, 어떤 공식에도 미배선=死)는 건드리지 않음 → 이중합산 불가.
--
-- 멱등: 자연키(comp_cd, plt_siz_cd, print_opt_cd, proc_cd, min_qty) 기준 DELETE 후 재삽입.
--   ux_t_prc_comp_prices_nat_key 와 정합(clr_cd=NULL·siz_cd=NULL·apply_ymd 동일).
-- 비고: 실 COMMIT 전 digital-clr-dryrun.sql 로 ROLLBACK 검증 후 인간 승인.
-- ============================================================================

BEGIN;

-- 1) 기존 S1 디지털인쇄 단가행 전량 제거(흑백 106 + 오라벨양면 106 = 212).
--    삭제 대상은 comp_cd 로 한정(S1 만). S2 는 미배선이라 보존.
DELETE FROM t_prc_component_prices
 WHERE comp_cd = 'COMP_PRINT_DIGITAL_S1';

-- 2) 칼라 단가 verbatim 재삽입 (212행: 단면 band→POPT_000001, 양면 band→POPT_000002).
--    clr_cd/siz_cd/mat_cd/opt_cd/coat_side_cnt/bdl_qty/dim_vals = NULL.

-- 3) 사후검증(트랜잭션 내) — 칼라 국4절 단면/양면 qty1 = 4000 / 6000 이어야.
DO $$
DECLARE v_dan numeric; v_yang numeric;
BEGIN
  SELECT unit_price INTO v_dan  FROM t_prc_component_prices
   WHERE comp_cd='COMP_PRINT_DIGITAL_S1' AND plt_siz_cd='SIZ_000499'
     AND print_opt_cd='POPT_000001' AND min_qty=1;
  SELECT unit_price INTO v_yang FROM t_prc_component_prices
   WHERE comp_cd='COMP_PRINT_DIGITAL_S1' AND plt_siz_cd='SIZ_000499'
     AND print_opt_cd='POPT_000002' AND min_qty=1;
  IF v_dan <> 4000 OR v_yang <> 6000 THEN
    RAISE EXCEPTION '교정 검증 실패: 국4절 단면=% 양면=% (기대 4000/6000)', v_dan, v_yang;
  END IF;
  RAISE NOTICE '교정 검증 OK: 국4절 칼라 단면=% 양면=%', v_dan, v_yang;
END $$;

COMMIT;
